-- Idempotent import of the 24 repository-backed archive posts.
-- These rows have no author_id and are therefore read-only to regular users.

insert into public.posts (id, legacy_key, author_name, avatar_seed, title, body, tags, status, created_at)
values
('10000000-0000-4000-8000-000000000001','p01','浅草小猪观察员','pig-p01','浅草寺🏮 pignic 小贝咖啡','软乎乎的小猪一直用鼻子拱手心。',array['小猪','日常记录'],'published',now()-interval '24 days'),
('10000000-0000-4000-8000-000000000002','f01','今日审猪员','friend-1','审猪积累 38.0：小猪也要梳毛吗？','今天这只意外地很配合，刷了半天只会低头装没看见。',array['审猪积累','朋友混入中'],'published',now()-interval '23 days'),
('10000000-0000-4000-8000-000000000003','p02','审猪档案馆','pig-p02','审猪积累','是萌猪。cute pig。猪中顶流。完全的优质小猪。',array['审猪积累','可爱小猪'],'published',now()-interval '22 days'),
('10000000-0000-4000-8000-000000000004','f02','低像素猪','friend-2','低质量猪图 2.0','凌晨两点抓到一只贴脸观察的小猪。',array['低质量猪图','朋友混入中'],'published',now()-interval '21 days'),
('10000000-0000-4000-8000-000000000005','p03','Tom 的饲养员','pig-p03','Tom⁉️⁉️⁉️','今天也是被小猪可爱到的一天。',array['宠物猪','日常'],'published',now()-interval '20 days'),
('10000000-0000-4000-8000-000000000006','f03','猪猪配饰研究员','friend-3','猪猪发夹会自己挑主人吗？','回头一看，好像被两只小猪认领了。',array['日常记录','朋友混入中'],'published',now()-interval '19 days'),
('10000000-0000-4000-8000-000000000007','p04','Yuki 的小日常','pig-p04','Yuki：请不要扒拉我的嘴巴','Yuki 又挠痒啦，胖宝宝太可爱。',array['Yuki','宠物猪'],'published',now()-interval '18 days'),
('10000000-0000-4000-8000-000000000008','f04','困困小猪观察所','friend-4','我想念一头在咖啡店睡着的猪','五分钟后直接进入休眠模式。',array['日常记录','朋友混入中'],'published',now()-interval '17 days'),
('10000000-0000-4000-8000-000000000009','p05','低像素猪','pig-p05','低质量猪图','像素不够，猪味来凑。',array['低质量猪图','可爱小猪'],'published',now()-interval '16 days'),
('10000000-0000-4000-8000-000000000010','f05','诚实小猪鉴定员','friend-5','最老实的小猪！','看着确实很老实，但总感觉还有事情瞒着我。',array['审猪积累','朋友混入中'],'published',now()-interval '15 days'),
('10000000-0000-4000-8000-000000000011','p06','Rocky 观察所','pig-p06','我想念一头魔丸 Rocky','被轻轻戳几下就发脾气啦。',array['Rocky','宠物猪'],'published',now()-interval '14 days'),
('10000000-0000-4000-8000-000000000012','f06','猪猪用餐指南','friend-6','这只小猪会自己找勺子吗？','疑似正在研究猪猪餐具的正确用法。',array['日常记录','朋友混入中'],'published',now()-interval '13 days'),
('10000000-0000-4000-8000-000000000013','p07','Rocky 观察所','pig-p07','呱呱叫的 Rocky','今日份会叫的小猪。',array['Rocky','可爱小猪'],'published',now()-interval '12 days'),
('10000000-0000-4000-8000-000000000014','f07','小猪情绪观察员','friend-7','玩游戏输了以后的猪 be like','输掉以后原地委屈成一团。',array['低质量猪图','朋友混入中'],'published',now()-interval '11 days'),
('10000000-0000-4000-8000-000000000015','p08','Rocky 大王的随从','pig-p08','Rocky 大王👑','一定要听第二段。',array['Rocky','审猪积累'],'published',now()-interval '10 days'),
('10000000-0000-4000-8000-000000000016','f08','猪言猪语记录处','friend-8','请不要捂住我的嘴巴 2.0','刚准备发表重要意见，就被同伴当场强制静音。',array['审猪积累','朋友混入中'],'published',now()-interval '9 days'),
('10000000-0000-4000-8000-000000000017','p09','请勿随意代入','pig-p09','请不要把小猪代入任何人','小猪不是调情工具，小猪就是小猪。',array['小猪','日常记录'],'published',now()-interval '8 days'),
('10000000-0000-4000-8000-000000000018','f09','小猪食堂巡查员','friend-9','你这只正在吃饭的猪！','吃青菜时被当场抓拍。',array['日常记录','朋友混入中'],'published',now()-interval '7 days'),
('10000000-0000-4000-8000-000000000019','p10','Soft Pig Club','pig-p10','Toy Story but make it soft🐽💤','柔软版玩具总动员。',array['可爱小猪','玩具'],'published',now()-interval '6 days'),
('10000000-0000-4000-8000-000000000020','f10','头顶生物研究所','friend-10','审猪积累 39.0：头顶长出一只？','低头玩手机的功夫，头顶突然被占领。',array['审猪积累','朋友混入中'],'published',now()-interval '5 days'),
('10000000-0000-4000-8000-000000000021','p11','小猪兄弟观察员','pig-p11','猪猪兄弟在干什么？','小猪兄弟今日份软乎乎。',array['小香猪','日常记录'],'published',now()-interval '4 days'),
('10000000-0000-4000-8000-000000000022','f11','小猪避暑办','friend-11','小猪也会热到变形吗？','出门五分钟就抱着风扇不撒手。',array['日常记录','朋友混入中'],'published',now()-interval '3 days'),
('10000000-0000-4000-8000-000000000023','p12','今天也在审猪','pig-p12','最棒的小猪！','蠢蠢的，很安心。',array['小猪','审猪积累'],'published',now()-interval '2 days'),
('10000000-0000-4000-8000-000000000024','f12','懂猪帝睡眠中心','friend-12','困困小猪找到专属枕头了','走到一半自动进入睡眠模式。',array['日常记录','朋友混入中'],'published',now()-interval '1 day')
on conflict (legacy_key) do update set
  title=excluded.title, body=excluded.body, author_name=excluded.author_name,
  avatar_seed=excluded.avatar_seed, tags=excluded.tags, status='published';

